"use strict";
// Arithmetic
let aa = 10 + 5; // 15
let bb = 10 - 3; // 7
let c = 4 * 3; // 12
let d = 10 / 2; // 5
let e = 10 % 3; // 1 (remainder)
// Assignment
let x = 5;
x += 3; // x = 8
x -= 1; // x = 7
// Comparison (Relational)
//In JS
//console.log(5 == "5");  // true  (loose - type coercion)
//console.log(5 === "5"); // false (strict - no coercion, use this!)
//console.log(5 != 3);    // true
console.log(5 > 3); // true
// Logical
console.log(true && false); // false (AND)
console.log(true || false); // true  (OR)
console.log(!true); // false (NOT/Negation)
// Ternary (shorthand if-else)
let ageNeww = 20;
let statusNew = ageNeww >= 18 ? "Adult" : "Minor";
// typeof
let val = "hello";
console.log(typeof val); // "string"
// Concatenation
let fullName = "John" + " " + "Doe"; // "John Doe"
